diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 427b8bd0e75a..18eba18eeba1 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -18881,7 +18881,34 @@ public:

     // Though the ultimate reduction may have multiple uses, its condition must
     // have only single use.
-    if (auto *Sel = dyn_cast<SelectInst>(Root))
+    if (auto *Sel = dyn_cast<SelectInst>(Root)) {
+      // Though the ultimate reduction may have multiple uses, its condition must
+      // have only single use.
+      if (!Sel->getCondition()->hasOneUse())
+        return false;
+      
+      // For boolean OR reductions involving selects that choose true, be conservative about poison.
+      if (RdxKind == RecurKind::Or) {
+        // Check if this is a poison-safe OR pattern: select cond, true, other
+        if ((isa<ConstantInt>(Sel->getTrueValue()) && 
+             cast<ConstantInt>(Sel->getTrueValue())->isOne()) ||
+            (isa<ConstantInt>(Sel->getFalseValue()) && 
+             cast<ConstantInt>(Sel->getFalseValue())->isOne())) {
+          // This select provides poison masking - don't vectorize
+          return false;
+        }
+      }
+    }
+      SelectInst *Sel = cast<SelectInst>(Root);
+      // Check if this is a poison-safe OR pattern: select cond, true, other
+      if ((isa<ConstantInt>(Sel->getTrueValue()) && 
+           cast<ConstantInt>(Sel->getTrueValue())->isOne()) ||
+          (isa<ConstantInt>(Sel->getFalseValue()) && 
+           cast<ConstantInt>(Sel->getFalseValue())->isOne())) {
+        // This select provides poison masking - don't vectorize
+        return false;
+      }
+    }
       if (!Sel->getCondition()->hasOneUse())
         return false;

